  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { Link } from 'react-router-dom-v5-compat';
  4	import {
  5	  ClipboardCopy,
  6	  ClipboardCopyVariant,
  7	  DescriptionList,
  8	  DescriptionListDescription,
  9	  DescriptionListGroup,
 10	  DescriptionListTerm,
 11	} from '@patternfly/react-core';
 12	import { RepositoryModel } from '../../models';
 13	import { PipelineRunKind } from '../../types';
 14	import {
 15	  RepoAnnotationFields,
 16	  RepositoryAnnotations,
 17	  RepositoryFields,
 18	  RepositoryLabels,
 19	} from '../../consts';
 20	import {
 21	  getGroupVersionKindForModel,
 22	  ResourceIcon,
 23	} from '@openshift-console/dynamic-plugin-sdk';
 24	import { getReferenceForModel } from '../pipelines-overview/utils';
 25	import { ExternalLink } from '../utils/link';
 26	import {
 27	  getGitProviderIcon,
 28	  getLabelValue,
 29	  sanitizeBranchName,
 30	} from '../utils/repository-utils';
 31	import { truncateMiddle } from '../utils/common-utils';
 32	
 33	export type RepositoryLinkListProps = {
 34	  pipelineRun: PipelineRunKind;
 35	};
 36	
 37	const RepositoryLinkList: React.FC<RepositoryLinkListProps> = ({
 38	  pipelineRun,
 39	}) => {
 40	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 41	  const plrLabels = pipelineRun.metadata.labels;
 42	  const plrAnnotations = pipelineRun.metadata.annotations;
 43	  const repoLabel = RepositoryLabels[RepositoryFields.REPOSITORY];
 44	  const repoName = plrLabels?.[repoLabel];
 45	  const repoURL =
 46	    plrAnnotations?.[RepositoryAnnotations[RepoAnnotationFields.REPO_URL]];
 47	  const shaURL =
 48	    plrAnnotations?.[RepositoryAnnotations[RepoAnnotationFields.SHA_URL]];
 49	  const branchName =
 50	    plrLabels?.[RepositoryAnnotations[RepoAnnotationFields.BRANCH]] ||
 51	    plrAnnotations?.[RepositoryAnnotations[RepoAnnotationFields.BRANCH]];
 52	
 53	  if (!repoName) return null;
 54	
 55	  return (
 56	    <DescriptionList className="pf-v6-u-mt-md">
 57	      <DescriptionListGroup>
 58	        <DescriptionListTerm>{t('Repository')}</DescriptionListTerm>
 59	        <DescriptionListDescription>
 60	          <div>
 61	            <ResourceIcon
 62	              groupVersionKind={getGroupVersionKindForModel(RepositoryModel)}
 63	            />
 64	            <Link
 65	              data-test="pl-repository-link"
 66	              to={`/k8s/ns/${
 67	                pipelineRun.metadata.namespace
 68	              }/${getReferenceForModel(RepositoryModel)}/${repoName}/Runs`}
 69	              className="co-resource-item__resource-name"
 70	            >
 71	              {repoName}
 72	            </Link>
 73	          </div>
 74	          {repoURL && (
 75	            <ExternalLink href={repoURL}>
 76	              {getGitProviderIcon(repoURL)} {repoURL}
 77	            </ExternalLink>
 78	          )}
 79	        </DescriptionListDescription>
 80	      </DescriptionListGroup>
 81	      {branchName && (
 82	        <DescriptionListGroup>
 83	          <DescriptionListTerm>
 84	            {t(getLabelValue(branchName, t))}
 85	          </DescriptionListTerm>
 86	          <DescriptionListDescription data-test="pl-repository-branch">
 87	            {sanitizeBranchName(branchName)}
 88	          </DescriptionListDescription>
 89	        </DescriptionListGroup>
 90	      )}
 91	      {plrLabels?.[RepositoryLabels[RepositoryFields.SHA]] && (
 92	        <DescriptionListGroup>
 93	          <DescriptionListTerm>{t('Commit id')}</DescriptionListTerm>
 94	          <DescriptionListDescription>
 95	            {shaURL ? (
 96	              <ExternalLink href={shaURL} data-test="pl-sha-url">
 97	                {truncateMiddle(
 98	                  plrLabels[RepositoryLabels[RepositoryFields.SHA]],
 99	                  {
100	                    length: 7,
101	                    truncateEnd: true,
102	                    omission: '',
103	                  },
104	                )}
105	              </ExternalLink>
106	            ) : (
107	              <ClipboardCopy
108	                data-test="pl-commit-id"
109	                variant={ClipboardCopyVariant.inlineCompact}
110	              >
111	                {plrLabels[RepositoryLabels[RepositoryFields.SHA]]}
112	              </ClipboardCopy>
113	            )}
114	          </DescriptionListDescription>
115	        </DescriptionListGroup>
116	      )}
117	      {plrLabels?.[RepositoryLabels[RepositoryFields.EVENT_TYPE]] && (
118	        <DescriptionListGroup>
119	          <DescriptionListTerm>{t('Event type')}</DescriptionListTerm>
120	          <DescriptionListDescription data-test="pl-event-type">
121	            {plrLabels[RepositoryLabels[RepositoryFields.EVENT_TYPE]]}
122	          </DescriptionListDescription>
123	        </DescriptionListGroup>
124	      )}
125	    </DescriptionList>
126	  );
127	};
128	
129	export default RepositoryLinkList;

